import $ from 'jquery';
import {Edge} from 'butterfly-dag';

class BaseEdge extends Edge {
  draw(obj) {
    let path = super.draw(obj);
    if (this.options.color) {
      $(path).addClass(this.options.color);
    }
    return path;
  }

  drawArrow(isShow) {
    let dom = super.drawArrow(isShow);
    if (this.options.color) {
      $(dom).addClass(this.options.color);
    }
    return dom;
  }

  drawLabel(text) {
    let dom = null;
    if (text) {
      dom = $(`<i class="newIconfont iconjiandao-tianchong label ${text}"></i>`)[0];
    }
    return dom;
  }
}

export default BaseEdge;

import React from 'react';
import ReactDOM from 'react-dom';
import {Canvas} from 'butterfly-dag';

import mockData from './data';

import './index.less';
import 'butterfly-dag/dist/index.css';

class Flow extends React.Component {
  constructor() {
    super();
    this.canvas = null;
  }

  componentDidMount() {
    // css里面的类名限制太死了
    let root = document.getElementById('dag-canvas');
    this.canvas = new Canvas({
      root: root,
      disLinkable: true, // 可删除连线
      linkable: false,    // 可连线
      draggable: true,   // 可拖动
      zoomable: true,    // 可放大
      moveable: true,    // 可平移
      theme: {
        edge: {
          shapeType: 'AdvancedBezier',
        }
      }
    });
    this.canvas.draw(mockData);
  }

  render() {
    return (
      <div className='flow-page'>
        <div className="flow-canvas" id="dag-canvas">
        </div>
      </div>
    );
  }
}

ReactDOM.render(<Flow />, document.getElementById('root'));

@import 'theme.less'; 


.flow-page {
  height: 100%;
  width: 100%;
  .flow-canvas {
    position: relative;
    height: 100%;
    width: 100%;
  }
  .label {
    position: absolute;
    font-size: 20px;
    background: none;
    border: none;
    box-shadow: none;
    line-height: 23px;
    color: @butterfly-line-color;
  }
  .label:hover {
    background: none;
    border: none;
    color: @butterfly-primary-color;
  }
  .rotate-left {
    transform: rotate(180deg);
  }
  .rotate-down {
    transform: rotate(90deg);
  }
  .rotate-right {
    transform: rotate(0deg);
  }
}

import $ from 'jquery';
import {Node} from 'butterfly-dag';

import './node.less';
class BaseNode extends Node {
  constructor(opts) {
    super(opts);
    this.options = opts;
  }

  draw = (opts) => {
    const container = $('<div class="flow-base-node"></div>')
      .css('top', opts.top)
      .css('left', opts.left)
      .attr('id', opts.id);

    const logoContainer = $(`<div class="logo-containe"><i class="iconfont ${opts.options.iconType}"><i/></div>`);

    const content = $('<div class="text"></div>').text(opts.options.label);

    container.append(logoContainer).append(content);

    return container[0];
  }
}

export default BaseNode;

@import 'theme.less'; 


.flow-base-node {
  position: absolute;
  width: 88px;
  height: 88px;
  padding: 5px;
  padding: 16px 0;
  background: @butterfly-theme-color;
  border: @butterfly-box-border;
  box-shadow: @butterfly-box-shadow;
  border-radius: 8px;
  .logo-containe { 
    width: 30px;
    height: 30px;
    background:@butterfly-primary-color;
    line-height: 30px;
    text-align: center;
    border-radius: 50%;
    margin: auto;
    margin-bottom: 8px;
    .iconfont {
      color: @butterfly-overlay-font-color;
    }
  }
  .text {
    font-size: 12px;
    color: @butterfly-normal-font-color;
    text-align: center;
  }
}

